#include <omp.h>
#include "common.h"

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

extern int omp_num_threads;

static void lud_diagonal_omp(float *m, int matrix_dim, int offset, int bs)
{
    float shadow[BLOCK_SIZE][BLOCK_SIZE];
    int i, j, row, col;

    for (row = 0; row < bs; row++) {
        for (col = 0; col < bs; col++) {
            shadow[row][col] = m[(offset + row) * matrix_dim + offset + col];
        }
    }

    for (i = 0; i < bs - 1; i++) {
        for (row = i + 1; row < bs; row++) {
            for (j = 0; j < i; j++) {
                shadow[row][i] -= shadow[row][j] * shadow[j][i];
            }
            shadow[row][i] /= shadow[i][i];
        }

        for (col = i + 1; col < bs; col++) {
            for (j = 0; j < i + 1; j++) {
                shadow[i + 1][col] -= shadow[i + 1][j] * shadow[j][col];
            }
        }
    }

    for (row = 1; row < bs; row++) {
        for (col = 0; col < bs; col++) {
            m[(offset + row) * matrix_dim + offset + col] = shadow[row][col];
        }
    }
}

static void lud_perimeter_block_omp(float *m, int matrix_dim, int offset, int bs,
                                    int block_start, int block_size)
{
    float dia[BLOCK_SIZE][BLOCK_SIZE];
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];
    int i, j, row, col;

    for (row = 0; row < bs; row++) {
        for (col = 0; col < bs; col++) {
            dia[row][col] = m[(offset + row) * matrix_dim + offset + col];
        }
    }

    for (row = 0; row < bs; row++) {
        for (col = 0; col < block_size; col++) {
            peri_row[row][col] = m[(offset + row) * matrix_dim + block_start + col];
        }
    }

    for (row = 0; row < block_size; row++) {
        for (col = 0; col < bs; col++) {
            peri_col[row][col] = m[(block_start + row) * matrix_dim + offset + col];
        }
    }

    for (col = 0; col < block_size; col++) {
        for (i = 1; i < bs; i++) {
            for (j = 0; j < i; j++) {
                peri_row[i][col] -= dia[i][j] * peri_row[j][col];
            }
        }
    }

    for (row = 0; row < block_size; row++) {
        for (i = 0; i < bs; i++) {
            for (j = 0; j < i; j++) {
                peri_col[row][i] -= peri_col[row][j] * dia[j][i];
            }
            peri_col[row][i] /= dia[i][i];
        }
    }

    for (row = 1; row < bs; row++) {
        for (col = 0; col < block_size; col++) {
            m[(offset + row) * matrix_dim + block_start + col] = peri_row[row][col];
        }
    }

    for (row = 0; row < block_size; row++) {
        for (col = 0; col < bs; col++) {
            m[(block_start + row) * matrix_dim + offset + col] = peri_col[row][col];
        }
    }
}

static void lud_internal_block_omp(float *m, int matrix_dim, int offset, int bs,
                                   int row_start, int row_size,
                                   int col_start, int col_size)
{
    int i, row, col;

    for (row = 0; row < row_size; row++) {
        for (col = 0; col < col_size; col++) {
            float sum = 0.0f;
            for (i = 0; i < bs; i++) {
                sum += m[(row_start + row) * matrix_dim + offset + i] *
                       m[(offset + i) * matrix_dim + col_start + col];
            }
            m[(row_start + row) * matrix_dim + col_start + col] -= sum;
        }
    }
}

void lud_omp(float *m, int matrix_dim)
{
    int offset;

    if (omp_num_threads > 0) {
        omp_set_num_threads(omp_num_threads);
    }

    for (offset = 0; offset < matrix_dim; offset += BLOCK_SIZE) {
        int bs = MIN(BLOCK_SIZE, matrix_dim - offset);
        int remain = matrix_dim - (offset + bs);
        int num_blocks, b, by, bx;

        lud_diagonal_omp(m, matrix_dim, offset, bs);

        if (remain <= 0) {
            continue;
        }

        num_blocks = (remain + BLOCK_SIZE - 1) / BLOCK_SIZE;

#pragma omp parallel for private(b) schedule(static)
        for (b = 0; b < num_blocks; b++) {
            int block_start = offset + bs + b * BLOCK_SIZE;
            int block_size = MIN(BLOCK_SIZE, matrix_dim - block_start);
            lud_perimeter_block_omp(m, matrix_dim, offset, bs, block_start, block_size);
        }

#pragma omp parallel for collapse(2) private(by, bx) schedule(static)
        for (by = 0; by < num_blocks; by++) {
            for (bx = 0; bx < num_blocks; bx++) {
                int row_start = offset + bs + by * BLOCK_SIZE;
                int col_start = offset + bs + bx * BLOCK_SIZE;
                int row_size = MIN(BLOCK_SIZE, matrix_dim - row_start);
                int col_size = MIN(BLOCK_SIZE, matrix_dim - col_start);
                lud_internal_block_omp(m, matrix_dim, offset, bs,
                                       row_start, row_size, col_start, col_size);
            }
        }
    }
}
